"use client";

import { useState, useCallback } from "react";

interface InsightsResult {
  insights: string[];
  recommendations: string[];
  alerts: string[];
}

export default function IAPage() {
  const [result, setResult] = useState<InsightsResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchInsights = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/ai/insights", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({}),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(
          (err as { error?: string }).error ?? `Erro ${res.status}`
        );
      }
      const json = (await res.json()) as { data: InsightsResult };
      setResult(json.data);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Erro desconhecido");
    } finally {
      setLoading(false);
    }
  }, []);

  return (
    <div className="p-8 max-w-6xl mx-auto w-full animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="mb-8">
        <h1 className="font-[family-name:var(--font-display)] text-4xl font-light text-[var(--color-text-primary)] tracking-tight">
          IA Clínica
        </h1>
        <p className="text-[14px] text-[var(--color-text-muted)] mt-1 font-light">
          Análise inteligente da sua carteira de pacientes usando IA avançada
        </p>
      </div>

      {/* Action */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-7 mb-6 glass-panel relative overflow-hidden group">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-4 relative z-10">
          <div>
            <div className="text-[16px] text-[var(--color-text-primary)] font-medium mb-1">
              🧠 Análise de Carteira
            </div>
            <div className="text-[13px] text-[var(--color-text-muted)] font-light leading-relaxed max-w-2xl">
              Gera insights, recomendações e alertas baseados nos dados das sessões recentes.
            </div>
          </div>
          <button
            type="button"
            onClick={fetchInsights}
            disabled={loading}
            className={`px-7 py-3 rounded-xl font-medium text-[14px] flex items-center justify-center gap-2 transition-all duration-300 ${
              loading 
                ? "bg-[var(--color-surface-hover)] text-[var(--color-text-muted)] cursor-not-allowed" 
                : "bg-[var(--color-brand)] text-[#060E09] hover:bg-[var(--color-brand)]/90 hover:shadow-[0_0_20px_rgba(var(--color-brand-rgb),0.3)] cursor-pointer"
            }`}
          >
            {loading ? (
              <>
                <span className="inline-block w-4 h-4 border-2 border-[var(--color-text-muted)] border-t-transparent rounded-full animate-spin" />
                Analisando...
              </>
            ) : (
              "Gerar Análise"
            )}
          </button>
        </div>

        <div className="text-[11px] text-[var(--color-text-muted)] px-3 py-2 bg-[var(--color-surface-hover)] rounded-lg border border-[var(--color-border-subtle)] w-fit flex items-center gap-2 relative z-10">
          <span className="text-[#fbbf24]">💡</span> Limite: 10 requisições/min · Modelo configurado no onboarding
        </div>
        
        {/* Decorative background glow */}
        <div className="absolute -bottom-24 -right-24 w-64 h-64 bg-[var(--color-brand)] opacity-[0.03] blur-3xl rounded-full group-hover:opacity-[0.06] transition-opacity duration-700 pointer-events-none" />
      </div>

      {/* Error */}
      {error && (
        <div className="px-5 py-4 bg-[#f87171]/10 border border-[#f87171]/30 rounded-xl text-[#f87171] text-[14px] mb-5 animate-[fadeUp_.3s_ease-out_both] flex items-center gap-3">
          <span className="text-[18px]">❌</span> {error}
        </div>
      )}

      {/* Results */}
      {result && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-[fadeUp_.4s_ease-out_both]">
          {/* Insights */}
          <InsightCard
            title="💡 Insights"
            items={result.insights}
            tone="brand"
            fullWidth={false}
          />

          {/* Recommendations */}
          <InsightCard
            title="📌 Recomendações"
            items={result.recommendations}
            tone="amber"
            fullWidth={false}
          />

          {/* Alerts */}
          {result.alerts.length > 0 && (
            <div className="lg:col-span-2">
              <InsightCard
                title="⚠️ Alertas"
                items={result.alerts}
                tone="danger"
                fullWidth
              />
            </div>
          )}
        </div>
      )}

      {/* Empty state */}
      {!result && !error && !loading && (
        <div className="text-center py-20 px-5 glass-panel rounded-2xl border border-[var(--color-border-subtle)] mt-8 animate-[fadeUp_.5s_ease-out_both]">
          <div className="text-[56px] mb-4 opacity-80">🧠</div>
          <div className="font-[family-name:var(--font-display)] text-[24px] text-[var(--color-text-secondary)] font-light mb-2">
            Inteligência Artificial Clínica
          </div>
          <div className="text-[14px] text-[var(--color-text-muted)] max-w-md mx-auto font-light leading-relaxed">
            Analise sua carteira de pacientes com IA. Receba insights sobre tendências,
            recomendações clínicas e alertas de risco.
          </div>
        </div>
      )}
    </div>
  );
}

function InsightCard({
  title,
  items,
  tone,
}: {
  title: string;
  items: string[];
  tone: "brand" | "amber" | "danger";
  fullWidth: boolean;
}) {
  if (items.length === 0) return null;

  const toneClasses: Record<
    "brand" | "amber" | "danger",
    { glow: string; heading: string; bar: string }
  > = {
    brand: {
      glow: "bg-[var(--color-brand)]",
      heading: "text-[var(--color-brand)]",
      bar: "border-[var(--color-brand)]/60",
    },
    amber: {
      glow: "bg-[#fbbf24]",
      heading: "text-[#fbbf24]",
      bar: "border-[#fbbf24]/70",
    },
    danger: {
      glow: "bg-[#f87171]",
      heading: "text-[#f87171]",
      bar: "border-[#f87171]/70",
    },
  };

  const toneCfg = toneClasses[tone];

  return (
    <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-6 glass-panel relative overflow-hidden group hover:border-[var(--color-border-strong)] transition-all duration-300">
      <div
        className={`absolute top-0 right-0 w-32 h-32 opacity-[0.03] rounded-bl-full group-hover:opacity-[0.06] transition-opacity duration-500 pointer-events-none ${toneCfg.glow}`}
      />
      <div className={`text-[14px] font-medium mb-4 flex items-center gap-2 relative z-10 ${toneCfg.heading}`}>
        {title}
      </div>
      <ul className="list-none flex flex-col gap-3 relative z-10 m-0 p-0">
        {items.map((item, i) => (
          <li
            key={i}
            className={`text-[13px] text-[var(--color-text-secondary)] border-l-2 pl-3.5 leading-relaxed ${toneCfg.bar}`}
          >
            {item}
          </li>
        ))}
      </ul>
    </div>
  );
}
